    if (alloc == "omp_cgroup_mem_alloc") return OMPC_ALLOCATE_ALLOCATOR_cgroup;
    if (alloc == "omp_pteam_mem_alloc") return OMPC_ALLOCATE_ALLOCATOR_pteam;
    if (alloc == "omp_thread_mem_alloc") return OMPC_ALLOCATE_ALLOCATOR_thread;
